#include <bits/stdc++.h>
using namespace std;
int main(){int n,k;scanf("%d %d",&n,&k);vector<int>coin(n);for(auto&c:coin)scanf("%d",&c);const int INF=1e9;vector<int>dp(k+1,INF);dp[0]=0;for(int c:coin)for(int v=c;v<=k;v++)if(dp[v-c]+1<dp[v])dp[v]=dp[v-c]+1;printf("%d\n",dp[k]>=INF?-1:dp[k]);}
